import { Registry } from '../core/zc-registry';
/**
 *
 * @param node
 * @return {number[]}
 */

export function getTranslationFromOwnerSVGElement(node) {
    if (node.isD3Selection) {
        node = node.node();
    }

    var ownerSVGElement = node.ownerSVGElement || node,
        translatedValue = [0, 0];

    while (node !== ownerSVGElement) {
        var translate = getSvgTransform(node).translate;
        translatedValue[0] += translate[0];
        translatedValue[1] += translate[1];
        node = node.parentNode;
    }

    return translatedValue;
}

function defined(obj) {
    return obj !== undefined && obj !== null;
}
/**
 *
 * @param element
 * @returns {{translate: Array, skew: Array, rotate: Number, scale: Array}}
 */
export function getSvgTransform(element) {
    // consolidate the SVGTransformList containing all transformations
    // to a single SVGTransform of type SVG_TRANSFORM_MATRIX and get
    // its SVGMatrix.

    if (element.isD3Selection) {
        element = element.node();
    }

    var baseVal = element.transform.baseVal.consolidate(),
        matrix = defined(baseVal) ? baseVal.matrix : null;

    if (defined(matrix)) {
        // Below calculations are taken and adapted from the private function
        // https://github.com/d3/d3-interpolate/blob/master/src/transform/decompose.js

        var a = matrix.a,
            b = matrix.b,
            c = matrix.c,
            d = matrix.d,
            e = matrix.e,
            f = matrix.f;

        var scaleX, scaleY, skewX;

        if ((scaleX = Math.sqrt(a * a + b * b))) {
            (a /= scaleX), (b /= scaleX);
        }

        if ((skewX = a * c + b * d)) {
            (c -= a * skewX), (d -= b * skewX);
        }

        if ((scaleY = Math.sqrt(c * c + d * d))) {
            (c /= scaleY), (d /= scaleY), (skewX /= scaleY);
        }

        if (a * d < b * c) {
            (a = -a), (b = -b), (skewX = -skewX), (scaleX = -scaleX);
        }
        return {
            translate: [e, f],
            skew: [(Math.atan2(b, a) * 180) / Math.PI, (Math.atan(skewX) * 180) / Math.PI],
            rotate: (Math.atan2(b, a) * 180) / Math.PI,
            scale: [scaleX, scaleY]
        };
    }

    return {
        translate: [0, 0],
        skew: [0, 0],
        rotate: 0,
        scale: [0, 0]
    };
}
Registry.setComponent('domUtils.getSvgTransform', getSvgTransform);

export function translateString(position, angle) {
    return `translate(${position.join(' ')})` + (defined(angle) ? ` rotate(${angle})` : '');
}
